const hs = $('Check HubSpot Connector').first().json;
const hz = $('Check Houzz Connector').first().json;
const api = $('Check API Health').first().json;

const links = [];
const broken = [];

// HubSpot connector
const hsStates = hs.sync_states || [];
const hsOk = hsStates.length > 0;
links.push({ name: 'HubSpot connector', ok: hsOk, detail: `${hsStates.length} entity states tracked` });
if (!hsOk) broken.push('HubSpot connector unreachable');

// Houzz connector
const hzStates = hz.sync_states || [];
const hzOk = hzStates.length > 0;
links.push({ name: 'Houzz connector', ok: hzOk, detail: `${hzStates.length} entity states tracked` });
if (!hzOk) broken.push('Houzz connector unreachable');

// API
const apiOk = api.status === 'healthy';
links.push({ name: 'HCI AI API', ok: apiOk, detail: api.status || 'unknown' });
if (!apiOk) broken.push(`API status: ${api.status}`);

const summary = broken.length === 0
  ? `All ${links.length} integrations reachable`
  : `${broken.length} integration(s) broken: ${broken.join('; ')}`;

return [{ json: { hasIssues: broken.length > 0, broken, links, summary } }];
